"""
MKT Original Language Commentary — Psalms chapters 111–117
Run: python3 scripts/zc-original-psalms-111-117.py

Source data used:
- data/interlinear/psalms.json
- data/translation/glossary-hebrew.json
- data/translation/draft/mediating/psalms.json

Key decisions in this range:
- Ps 111 + 112: twin acrostic psalms (each half-line begins with successive Hebrew letter);
  Ps 112 deliberately mirrors YHWH's attributes from Ps 111 onto the righteous person;
  rēʾshît ḥokhmāh yirʾat yhwh (v10) = identical to Prov 9:10, slightly different from
  Prov 1:7; rēʾshît = both "beginning" (entry point) and "chief/best part" (firstfruits)
- Ps 112:9 cited by Paul in 2 Cor 9:9 for Christian generosity
- Ps 113–118: the Egyptian Hallel sung at Passover (113–114 before the meal,
  115–118 after); Ps 113 deliberately echoes Hannah's song (1 Sam 2:7-8)
- Ps 114: unique in having no divine name until v7 — nature acts without naming its cause;
  ḥûl (writhe, be in anguish) in v7 = the earth in birth-pangs before God's presence
- Ps 115:17 (dead do not praise the LORD) is a key OT anthropology text — consistent
  with Ps 6:5, 88:10-12; NT resurrection hope inverts this reality
- Ps 116:10 cited in 2 Cor 4:13; yāqār in v15 means "costly/grievous" not "desirable"
- Ps 117 is the shortest psalm; v1 cited in Rom 15:11 for universal Gentile inclusion
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

# INTENT: mkt-original for Psalms 111-117 — twin acrostic psalms (111-112), the
#   Egyptian Hallel opening (113-118 partial), and the universal call of Ps 117.
# CHANGE? If commentary/mkt-original/psalms.json structure changes, update load_comm/save_comm.
# VERIFY: python3 -c "import json; d=json.load(open('data/commentary/mkt-original/psalms.json'));
#   [print(ch, len(d[ch])) for ch in ['111','112','113','114','115','116','117']]"

PSALMS = {
  "111": {
    "1": '<p><strong>hallĕlûyāh</strong> — the psalm opens with the liturgical interjection that will frame the entire Egyptian Hallel (Ps 113–118). The term is a third-person plural imperative fused with the divine name: <em>hallĕlû</em> (praise, pl.) + <em>yāh</em> (the LORD). It stands outside the acrostic structure proper, which begins with <em>ʾôdeh yhwh</em>.</p><p><strong>ʾôdeh yhwh bĕkhol-lēbāb</strong> — <em>ʾôdeh</em> is Hiphil of <em>yādāh</em> (to cast, throw), which came to mean "acknowledge" then "thank/praise." The phrase <em>bĕkhol-lēbāb</em> (with the whole heart) sets the register: total personal engagement, not rote liturgy. Ps 111 and 112 are twin acrostic poems — each of the 22 half-lines begins with successive Hebrew letters (aleph through taw).</p>',
    "2": '<p><strong>gĕdōlîm maʿăśê yhwh</strong> — the acrostic continues: <em>gimel</em> opens this half-line. <strong>dĕrûšîm lĕkhol-ḥepṣêhem</strong> — <em>dĕrûšîm</em> is a passive participle of <em>dāraš</em> (to seek, study, inquire) — the works of the LORD are "being studied/sought out" by those who delight in them. This is not passive contemplation but active investigation; the same verb is used of studying Torah (Ezra 7:10).</p>',
    "3": '<p><strong>hōd-wĕhādār pĕʿullātô</strong> — <em>hōd</em> (splendor, majesty) and <em>hādār</em> (honor, glory, adornment) are often paired for the royal appearance of kings; here applied to YHWH\'s deeds. <strong>wĕṣidqātô ʿōmedet lāʿad</strong> — his righteousness "stands forever" — the participle <em>ʿōmedet</em> conveys ongoing, present standing. This phrase recurs word-for-word in Ps 112:3 and 112:9 applied to the righteous person — the mirroring is deliberate.</p>',
    "4": '<p><strong>zēkher ʿāśāh lĕniplĕʾōtāyw</strong> — "he made a memorial/remembrance for his wonderful works." <em>zēkher</em> (memorial, remembrance) is the word behind commemorative ritual — Passover, the feasts, and later Eucharist all operate as <em>zēkher</em>. <strong>ḥannûn wĕraḥûm yhwh</strong> — the same paired attributes as Exod 34:6, the foundational divine self-disclosure at Sinai. Ps 111 takes these attributes and distributes them through the psalm; Ps 112 applies them to the righteous person.</p>',
    "5": '<p><strong>ṭeref nātan lîrēʾāyw</strong> — <em>ṭeref</em> literally means torn prey — what a wild animal has seized and torn. Used here for the provision God gives to those who fear him; the raw word choice suggests generous, abundant feeding, not measured rations. <strong>yizkōr lĕʿōlām bĕrîtô</strong> — "he will be mindful forever of his covenant" — <em>zākar</em> (remember) in the OT is never merely cognitive; divine remembering means divine action on behalf of the covenant.</p>',
    "6": '<p><strong>kōaḥ maʿăśāyw higgîd lĕʿammô</strong> — "the power of his works he has declared to his people" — <em>higgîd</em> (Hiphil of <em>nāgad</em>, to make clear, declare) implies formal proclamation; the Exodus is the paradigm. <strong>lātēt lāhem naḥălat gôyim</strong> — to give them the nations\' inheritance/possession. <em>naḥălāh</em> (inheritance, possession) carries the kinship/family estate meaning — the land given to Israel is a family grant from the divine father, not merely a military conquest.</p>',
    "7": '<p><strong>maʿăśê yādāyw ʾĕmet ûmišpāṭ</strong> — "the works of his hands are faithfulness (<em>ʾĕmet</em>) and justice (<em>mišpāṭ</em>)" — the two together form a hendiadys for covenant order. <em>ʾĕmet</em> = truth/faithfulness (relational reliability); <em>mišpāṭ</em> = right judgment/justice (legal reliability). <strong>neʾĕmānîm kol-piqûdāyw</strong> — "all his precepts are trustworthy" — <em>neʾĕmānîm</em> = Niphal participle of <em>ʾāman</em> (to be firm, reliable) — the cognate of <em>ʾāmēn</em>.</p>',
    "8": '<p><strong>sĕmûkhîm lāʿad lĕʿôlām</strong> — "upheld/supported for ever and ever" — <em>sāmak</em> means to lean on, support, prop up; the precepts of YHWH are themselves load-bearing structures. <strong>ʿăśûyim bĕʾĕmet wĕyāšār</strong> — "done/made in faithfulness and uprightness" (<em>yāšār</em> = straight, right, upright).</p>',
    "9": '<p><strong>pĕdût šālaḥ lĕʿammô</strong> — "redemption (<em>pĕdût</em>) he sent to his people" — <em>pĕdût</em> is related to <em>pādāh</em> (to ransom, redeem by payment), distinct from <em>gĕʾullāh</em> (kinship redemption). The verb <em>šālaḥ</em> (send, commission) gives the redemption a missional character — it was dispatched. <strong>ṣiwwāh-lĕʿōlām bĕrîtô</strong> — "he commanded his covenant forever" — <em>ṣiwwāh</em> (command) used with the covenant is striking: the covenant is not merely offered but decreed. <strong>qādôš wĕnôrāʾ šĕmô</strong> — "holy and awesome/fearful is his name" — the psalm\'s climax before the concluding wisdom formula.</p>',
    "10": '<p><strong>rēʾshît ḥokhmāh yirʾat yhwh</strong> — "the beginning/chief part of wisdom is the fear of the LORD." <em>rēʾshît</em> can mean either "beginning" (first step, entry point) or "the best/foremost part" (as in firstfruits, Gen 1:1). Both meanings apply: fearing the LORD is where wisdom starts and also its highest expression. This clause appears nearly verbatim in Prov 9:10 and (slightly varied) in Prov 1:7, marking Ps 111 as part of the wisdom tradition. The acrostic ends with <em>taw</em> in the final word <em>tĕhillātô</em> (his praise): the whole alphabet praises him.</p>',
  },
  "112": {
    "1": '<p><strong>hallĕlûyāh ʾašrê-ʾîš yārēʾ ʾet-yhwh</strong> — Ps 112 opens with the same <em>hallĕlûyāh</em> as Ps 111, then immediately echoes Ps 111\'s closing formula: "blessed is the man who fears the LORD" mirrors "the fear of the LORD is the beginning of wisdom" (111:10). The two psalms are a diptych: Ps 111 describes YHWH\'s character; Ps 112 maps those same attributes onto the righteous person who fears him. <strong>bĕmiṣwōtāyw ḥāpēṣ mĕʾōd</strong> — "who greatly delights in his commandments" — <em>ḥāpēṣ</em> (to take pleasure in) is the same word as Ps 111:2 ("those who find pleasure in them"). The acrostic begins anew with aleph.</p>',
    "2": '<p><strong>gibbôr bāʾāreṣ yihyeh zarʿô</strong> — "mighty/powerful in the land will be his seed" — <em>gibbôr</em> is the word for warrior, hero (used of Boaz in Ruth 2:1). Here it denotes the social standing and influence the righteous man\'s descendants will carry. <strong>dôr yĕšārîm yĕbōrāk</strong> — "the generation of the upright will be blessed" — <em>yĕšārîm</em> (the upright) = those aligned with covenant order.</p>',
    "3": '<p><strong>hôn-wāʿōšer bĕbêtô</strong> — "wealth and riches are in his house" — the wisdom tradition presents material blessing as a regular outcome of covenant faithfulness, without denying that the righteous sometimes suffer. <strong>wĕṣidqātô ʿōmedet lāʿad</strong> — "and his righteousness stands forever" — verbatim repetition from Ps 111:3 (there said of YHWH\'s work). The transfer is deliberate: the righteous person shares in a righteousness with the permanence of YHWH\'s own.</p>',
    "4": '<p><strong>zāraḥ baḥōšek ʾôr layyĕšārîm</strong> — "there rises/shines in the darkness a light for the upright" — <em>zāraḥ</em> is the verb for sunrise; it images a dawn breaking on those sitting in darkness. <strong>ḥannûn wĕraḥûm wĕṣaddîq</strong> — in Ps 111:4 these three attributes (gracious, compassionate, righteous) describe YHWH; here they describe the righteous person. The structural mirroring is the psalm\'s point: the one who fears YHWH takes on the divine character.</p>',
    "5": '<p><strong>ṭôb-ʾîš ḥônēn ûmalweh</strong> — "it goes well with a man who shows favor and lends" — <em>ḥānan</em> (to show favor, be gracious) in the Qal is the human equivalent of what YHWH does in divine grace. The wisdom tradition consistently praises generosity: Ps 37:26 says "he is always generous and lends." <strong>yĕkhalkēl dĕbārāyw bĕmišpāṭ</strong> — "he manages his affairs with justice/right judgment" — the righteous person\'s practical dealings are ordered by <em>mišpāṭ</em>.</p>',
    "6": '<p><strong>kî-lĕʿôlām lōʾ yimmôṭ</strong> — "for to eternity he will not be shaken/moved" — <em>māṭaṭ</em> (to waver, totter) is the same verb used of cosmic shaking (Ps 46:6); the righteous person has the stability that belongs to the foundations of the world. <strong>lĕzēkher ʿôlām yihyeh ṣaddîq</strong> — "in everlasting remembrance will be the righteous" — to be remembered is to have one\'s deeds still operating; to be forgotten is a form of death.</p>',
    "7": '<p><strong>miššĕmûʿāh rāʿāh lōʾ yîrāʾ</strong> — "of evil report he will not be afraid" — the righteous person is not destabilized by catastrophic news because his foundation is not circumstantial. <strong>nākôn libbô bāṭûaḥ bayhwāh</strong> — "his heart is established/firm, trusting in the LORD" — <em>nākôn</em> (Niphal of <em>kûn</em>, to be established, fixed) describes a settled, prepared heart. <em>bāṭûaḥ</em> (trusting, secure) is the disposition that makes fearlessness possible.</p>',
    "8": '<p><strong>sāmûk libbô lōʾ yîrāʾ</strong> — "his heart is supported/braced; he will not fear" — <em>sāmak</em> (to lean on, support, prop) — from the same root as Ps 111:8. The heart propped up by God is the heart that will not fear. <strong>ʿad ʾăšer yirʾeh bĕṣārāyw</strong> — "until he sees (what happens to) his enemies" — the righteous person will outlast those arrayed against him.</p>',
    "9": '<p><strong>pizzar nātan lāʾebyônîm</strong> — "he scattered, he gave to the poor" — <em>pizzar</em> (Piel of <em>pāzar</em>) means to scatter, disperse, spread abroad — a vivid image of open-handed, non-calculated giving. Paul quotes this verse in 2 Cor 9:9 when arguing for generous Christian giving: <em>"He has distributed freely, he has given to the poor; his righteousness endures forever."</em> Paul applies this OT description of the righteous person to the generous believer. <strong>ṣidqātô ʿōmedet lāʿad</strong> — the third occurrence of this clause across the two psalms (111:3, 112:3, 112:9), now said of the generous giver.</p>',
    "10": '<p><strong>rāšāʿ yirʾeh wĕkāʿas</strong> — "the wicked will see and be vexed/angry" — the final letter of the acrostic (<em>taw</em>) is in <em>taʾăwat rĕšāʿîm</em> (the desire of the wicked). <strong>šinnāyw yaḥărōq wĕnāmās</strong> — "he will gnash his teeth and melt away" — <em>ḥārak</em> (to grind teeth, used of hostility in Ps 37:12) and <em>māsas</em> (to melt, dissolve). <strong>taʾăwat rĕšāʿîm tōʾbēd</strong> — "the desire of the wicked will perish" — the closing antithesis to v6\'s "everlasting remembrance": the wicked leave no lasting trace.</p>',
  },
  "113": {
    "1": '<p><strong>hallĕlû ʿabdê yhwh hallĕlû ʾet-šēm yhwh</strong> — the triple repetition of <em>hallĕlû</em> opens Ps 113 with liturgical intensity; this is the first of the Egyptian Hallel psalms (113–118) sung at Passover. The address is <em>ʿabdê yhwh</em> (servants of the LORD) — corporate Israel understood as YHWH\'s household. <em>šēm yhwh</em> (the name of the LORD) — to praise the name is to praise the character and presence as revealed, not merely a label. This distinction matters: the nations will eventually praise this name (Ps 117; Rom 15:11).</p>',
    "2": '<p><strong>yĕhî šēm yhwh mĕbōrāk mēʿattāh wĕʿad-ʿôlām</strong> — "may the name of the LORD be blessed from now and until forever" — the jussive <em>yĕhî</em> (let it be) frames this as prayer, not merely description. The temporal span <em>mēʿattāh wĕʿad-ʿôlām</em> (from this moment and unto eternity) appears also in Ps 115:18 and 121:8, making it a standard formula for eschatological praise.</p>',
    "3": '<p><strong>mimmizraḥ-šemeš ʿad-mĕbōʾô mĕhullāl šēm yhwh</strong> — "from the rising of the sun to its setting, praised is the name of the LORD" — spatial universality (east to west) complements the temporal universality of v2. The passive participle <em>mĕhullāl</em> (praised, being praised) suggests an already-existing reality: the name is universally worthy of praise as a present fact. Mal 1:11 echoes this: YHWH declares that his name is great among the nations from east to west.</p>',
    "4": '<p><strong>rām ʿal-kol-gôyim yhwh ʿal-haššāmayim kĕbôdô</strong> — "the LORD is high above all nations; above the heavens is his glory" — <em>rām</em> (Qal participle of <em>rûm</em>, to be high) is simple in Hebrew but sweeping in claim: YHWH stands above every political and religious sovereignty. Even the heavens, the highest created reality, are below his glory. The transcendence established here (vv4-5) makes the condescension of vv6-9 all the more radical.</p>',
    "5": '<p><strong>mî kayhwāh ʾĕlōhênû haggābihî lāšābet</strong> — "who is like the LORD our God, who is enthroned so high (<em>haggābihî lāšābet</em>)?" — the rhetorical question expects no answer. <em>haggābihî</em> is the Hiphil participle of <em>gābah</em> (to be high, to raise high): he who makes his seat high. The idiom "high to sit/dwell" emphasizes his enthronement at the apex of creation — precisely the one who then bends down in vv6-9.</p>',
    "6": '<p><strong>hammašpîlî lirʾôt baššāmayim ûbāʾāreṣ</strong> — "who lowers himself to look at the heavens and the earth" — <em>hammašpîlî</em> (Hiphil participle of <em>šāpal</em>, to be low, humble) — God must lower himself to look even at the heavens. The condescension is absolute: the one enthroned above heaven bends down so far that even the sky is below his sight-line. This framing makes vv7-9 theologically radical: his attention to the poor is an act of infinite descent.</p>',
    "7": '<p><strong>mĕqîmî mēʿāpār dāl mēʾašpōt yārîm ʾebyôn</strong> — "raising the poor from the dust, lifting the needy from the ash heap" — the vocabulary is nearly identical to 1 Sam 2:8 (Hannah\'s song). The <em>ʾašpōt</em> (ash heap, dunghill) in ancient villages was the rubbish heap outside the village where the destitute scavenged — a specific social location, not a metaphor. Ps 113 deliberately evokes Hannah\'s song, connecting YHWH\'s saving action with the OT pattern of reversal (Sarah, Rebekah, Rachel, Hannah, Elizabeth). Luke 1:52-53 (the Magnificat) continues this pattern.</p>',
    "8": '<p><strong>lĕhôšîbî ʿim-nĕdîbîm ʿim nĕdîbê ʿammô</strong> — "to seat him with princes, with the princes of his people" — <em>nādîb</em> (prince, noble, willing giver) has dual meaning: nobility by birth and liberality of spirit. The God who lifts the poor from the ash heap seats them in the company of the nobility. This is not social revolution through violence but divine reversal through grace — the same pattern appears in the Magnificat and in Jesus\' beatitudes.</p>',
    "9": '<p><strong>mōšîbî ʿăqeret habbayit ʾēm-habbānîm śĕmēḥāh</strong> — "who gives the barren one of the house a home, a joyful mother of children" — <em>ʿăqeret</em> (barren woman, from <em>ʿāqar</em>, to root up/hamstring) — one who has been uprooted from the social role of motherhood. Her transformation into <em>ʾēm-habbānîm śĕmēḥāh</em> (a joyful mother of children) closes the psalm on the note of reversal. The barren woman\'s transformation is the paradigm of all the divine reversals in the Psalter.</p>',
  },
  "114": {
    "1": '<p><strong>bĕṣēʾt yiśrāʾēl mimmimṣrāyim bêt yaʿăqōb mēʿam lōʿēz</strong> — "when Israel went out from Egypt, the house of Jacob from a people of <em>lōʿēz</em>" — <em>lōʿēz</em> (from <em>lāʿag</em>, to mock, stammer, speak unintelligibly) describes Egypt as a place of foreign/incomprehensible speech, a domain linguistically alien to Israel. The choice of this word marks Egypt as beyond the covenant world. The LXX renders it <em>barbarophōnou</em> (barbarous-speaking people), the etymological source of the Greek word "barbarian."</p>',
    "2": '<p><strong>hāyĕtāh yĕhûdāh lĕqodšô yiśrāʾēl mamšĕlôtāyw</strong> — "Judah became his sanctuary, Israel his dominion/kingdom" — the verb <em>hāyĕtāh</em> (became, feminine — the country is meant, not the tribe) marks transformation: the land was not always holy but became so through election. The divine name does not appear in this psalm until v7 — everything happens as nature reacting to an unnamed force, building dramatic suspense.</p>',
    "3": '<p><strong>hayyām rāʾāh wayyānōs haywardēn yissōb lĕʾāḥôr</strong> — "the sea saw and fled; the Jordan turned back/reversed" — the Red Sea crossing (Exod 14) and Jordan crossing (Josh 3-4) are compressed into one dramatic moment. The verb <em>yānûs</em> (to flee, run away) — the sea is terrified and runs; <em>yissōb lĕʾāḥôr</em> (to turn back to the rear) — the Jordan\'s flow is reversed. No Moses, no Joshua is named — only creation\'s immediate response to divine presence.</p>',
    "4": '<p><strong>hehārîm rāqĕdû kĕʾêlîm gĕbāʿôt kĕbnê-ṣōʾn</strong> — "the mountains leaped/danced like rams, the hills like young lambs" — <em>rāqad</em> (to skip, leap, dance; the same verb in Eccl 3:4 for dancing) applied to mountains achieves the psalm\'s signature comic-majestic effect. The simile domesticates the mountains into a flock responding to their shepherd — and sets up the interrogation of vv5-6.</p>',
    "5": '<p><strong>mah-lĕkā hayyām kî tānûs haywardēn tissōb lĕʾāḥôr</strong> — "what happened to you, O sea, that you fled? O Jordan, that you turned back?" — the psalm now speaks directly to the sea and the Jordan as if they could answer. The rhetorical questions (vv5-6) probe the cause of vv3-4, building dramatic suspense before the answer in v7.</p>',
    "6": '<p><strong>hehārîm tirqĕdû kĕʾêlîm gĕbāʿôt kĕbnê-ṣōʾn</strong> — "you mountains, why did you leap like rams? You hills, like young lambs?" — the same simile as v4, now turned interrogative. The repetition creates a chiastic structure: vv3-4 describe → vv5-6 interrogate → v7 answers. No answer is given to the sea or the mountains; the answer comes as a command to the earth itself.</p>',
    "7": '<p><strong>mippĕnê ʾādôn ḥûlî ʾāreṣ mippĕnê ʾĕlôah yaʿăqōb</strong> — "from before the Lord (<em>ʾādôn</em>), writhe in anguish O earth; from before the God of Jacob" — the divine name appears for the first time in v7. <em>ḥûl</em> (to writhe, to be in anguish) is the verb used for a woman in labor (Isa 26:17; Jer 22:23); the earth\'s response to YHWH\'s presence is birth-pangs, not merely trembling. The title <em>ʾĕlôah yaʿăqōb</em> (God of Jacob) emphasizes covenant particularity: the universal Lord is specifically Israel\'s covenant God.</p>',
    "8": '<p><strong>hahōpekhî haṣṣûr ʾăgam-māyim ḥallāmîš lĕmaʿyĕnô-māyim</strong> — "the one who turns the rock into a pool of water, the flint into a spring of water" — a participial relative clause describing God\'s characteristic action. The reference is to the water-from-rock miracle at Meribah and Massah (Exod 17:1-7; Num 20:2-13). Paul allegorically identifies this rock with Christ in 1 Cor 10:4 ("the spiritual rock that followed them, and the rock was Christ"). <em>ḥallāmîš</em> (flint, the hardest stone) heightens the miracle: not ordinary rock but flint becomes a flowing spring.</p>',
  },
  "115": {
    "1": '<p><strong>lōʾ lānû yhwh lōʾ lānû kî-lĕšimĕkā tēn kābôd</strong> — "not to us, O LORD, not to us — but to your name give glory" — the double <em>lōʾ lānû</em> (not to us... not to us) is emphatic self-abnegation; the psalm opens by disavowing any claim to divine credit. The glory belongs to the divine name, grounded in two covenant attributes: <strong>ʿal-ḥasdĕkā ʿal-ʾămittĕkā</strong> — "for your steadfast love (<em>ḥesed</em>) and your faithfulness (<em>ʾĕmet</em>)" — the two pillars of covenantal divine character (Exod 34:6).</p>',
    "2": '<p><strong>lāmmāh yōʾmĕrû haggôyim ʾayyēh-nāʾ ʾĕlōhêhem</strong> — "why should the nations say, \'Where then is their God?\'" — the taunt may reflect military defeat or the challenge of Babylonian exile. The nations\' challenge is theological: a God who cannot be seen in a cult statue seems powerless by ancient Near Eastern standards. The psalm\'s response (vv3-8) is that YHWH\'s invisibility is not weakness but transcendence — and that visible idols are themselves the problem.</p>',
    "3": '<p><strong>wĕʾĕlōhênû baššāmayim kōl ʾăšer-ḥāpēṣ ʿāśāh</strong> — "but our God is in the heavens; all that he pleases he has done" — the contrast is absolute: the nations ask "Where?" and the answer is "in the heavens" — beyond all spatial localization. <em>kōl ʾăšer-ḥāpēṣ ʿāśāh</em> (all that he pleases he has done) — divine sovereignty over all events, contrasted with the impotence of idols that cannot even see or speak.</p>',
    "4": '<p><strong>ʿăṣabbêhem kesef wĕzāhāb maʿăśēh yĕdê ʾādām</strong> — "their idols are silver and gold — the work of human hands" — <em>ʿăṣabbîm</em> (idols, from <em>ʿāṣab</em>, to fashion/shape; also related to grief/pain) — the word choice for "idols" carries a derogatory connotation. The critique "work of human hands" is the core of the OT idol polemic: the material precedes the maker. Compare Isa 44:9-20 (the craftsman who burns half a tree for warmth and makes an idol with the other half) and Jer 10:1-16.</p>',
    "5": '<p><strong>peh-lāhem wĕlōʾ yĕdabbērû ʿênayim lāhem wĕlōʾ yirʾû</strong> — "they have mouths but do not speak; eyes they have but do not see" — the systematic dismemberment of the idol\'s sense organs (vv5-7) proceeds through mouth, eyes, ears, nose, hands, feet, and throat. The irony is double: the idol has the form of human sense organs that YHWH gave to humans, but the form is hollow — none of them function. The idol is a parody of the human being made in God\'s image, possessing the form but not the <em>nĕšāmāh</em> (breath of life).</p>',
    "6": '<p><strong>ʾoznayim lāhem wĕlōʾ yišmāʿû ʾap lāhem wĕlōʾ yĕrîḥûn</strong> — "ears they have but do not hear; a nose they have but do not smell" — the idol\'s nose is functionless in both biological and cultic terms: it cannot smell the sacrifices offered to it. The contrast with YHWH is implicit: YHWH smells Noah\'s sacrifice (Gen 8:21: <em>wayyāraḥ yhwh ʾet-rêaḥ hannîḥōaḥ</em>). The idol\'s organ exists but cannot engage with what is brought to it.</p>',
    "7": '<p><strong>yĕdêhem wĕlōʾ yĕmîšûn raglêhem wĕlōʾ yĕhallēkû lōʾ-yehgû bigrônām</strong> — "their hands but they cannot feel; their feet but they cannot walk; they do not make a sound from their throat" — <em>māšaš</em> (to feel, grope) — the hands lack tactile sensation. <em>hāgāh</em> (to mutter, meditate, make a sound) — used of the growl of a lion, the mourning of a dove, the murmur of Torah meditation (Ps 1:2). The idol\'s throat produces nothing — no growl, no word, no breath. The polemic ends with this most basic absence.</p>',
    "8": '<p><strong>kĕmôhem yihyû ʿōśêhem kōl ʾăšer-bōṭēaḥ bāhem</strong> — "like them will be those who make them — all who trust in them" — the idol polemic reaches its theological apex: worshippers become what they worship. If the idol is a non-seeing, non-hearing, non-breathing thing, the worshipper who trusts in it becomes correspondingly deaf, blind, and spiritually lifeless. This principle of worship-as-formation runs counter to the fear of the LORD in Ps 111-112, where the one who fears YHWH takes on YHWH\'s own character.</p>',
    "9": '<p><strong>yiśrāʾēl bĕṭaḥ bayhwāh ʿezrām ûmāginnām hûʾ</strong> — "Israel, trust in the LORD! He is their help and their shield" — the sudden shift from description to direct address (v9) is a liturgical pivot, probably call-and-response between cantor and congregation. The triple refrain (vv9/10/11) addresses Israel, the house of Aaron, and those who fear the LORD — the three groups present in the temple court. <em>ʿezer</em> (help) and <em>māgēn</em> (shield) are the two primary metaphors for divine protection: active assistance and defensive covering.</p>',
    "10": '<p><strong>bêt ʾahărōn bĕṭĕḥû bayhwāh ʿezrām ûmāginnām hûʾ</strong> — "house of Aaron, trust in the LORD! He is their help and their shield" — the <em>bêt ʾahărōn</em> (house of Aaron) = the priestly families. Their trust is placed in the same source as all Israel: the LORD, not their priestly status or ritual expertise. The identical refrain drives home that there is one source of help and protection for all.</p>',
    "11": '<p><strong>yirʾê yhwh bĕṭĕḥû bayhwāh ʿezrām ûmāginnām hûʾ</strong> — "those who fear the LORD, trust in the LORD! He is their help and their shield" — the third group, <em>yirʾê yhwh</em> (those who fear the LORD), may refer to Gentile proselytes or God-fearers in the temple court (cf. Acts 10:2, 13:16), expanding the circle beyond ethnic Israel. Together the triple refrain says: whatever your status, your help is not in idols but in the living God.</p>',
    "12": '<p><strong>yhwh zĕkhārānû yĕbārēk</strong> — "the LORD has remembered us; he will bless" — <em>zĕkhārānû</em> (he has remembered us) — divine remembering always entails divine acting; it is not a cognitive event but a covenant event. The past tense grounds the future blessing: because he has already remembered, the threefold blessing that follows is certain. The triple <em>yĕbārēk</em> (he will bless) echoes the triple refrain of vv9-11.</p>',
    "13": '<p><strong>yĕbārēk yirʾê yhwh haqqĕṭannîm ʿim-haggĕdōlîm</strong> — "he will bless those who fear the LORD, the small together with the great" — the pairing <em>haqqĕṭannîm ʿim-haggĕdōlîm</em> (the small together with the great) emphasizes that the blessing is not status-based. The fear of the LORD is democratizing: it places the small and the great on the same footing before the divine patron.</p>',
    "14": '<p><strong>yōsēp yhwh ʿălêkem ʿălêkem wĕʿal-bĕnêkem</strong> — "may the LORD increase you — you and your children" — <em>yāsap</em> (to add, increase) — the blessing is multigenerational increase, harking back to the Abrahamic promise (<em>pārāh wĕrābāh</em>, be fruitful and multiply, Gen 1:28; 9:1). The Hiphil jussive: "may he cause you to increase."</p>',
    "15": '<p><strong>bĕrûkhîm ʾattem layhwāh ʿōśēh šāmayim wāʾāreṣ</strong> — "blessed are you by/from the LORD, who made heaven and earth" — the divine title <em>ʿōśēh šāmayim wāʾāreṣ</em> (maker of heaven and earth) appears also in Ps 121:2 and 124:8. The idol critique (vv4-8) makes this doxology sharper: unlike idols made by human hands, Israel is blessed by the one who made all that is.</p>',
    "16": '<p><strong>haššāmayim šāmayim layhwāh wĕhāʾāreṣ nātan libnê-ʾādām</strong> — "the heavens — heavens — belong to the LORD, but the earth he has given to the children of man" — the repeated <em>haššāmayim šāmayim</em> is emphatic: the upper realm is reserved for YHWH alone. But the earth is given (<em>nātan</em>, perfect tense — permanent grant) to <em>bĕnê-ʾādām</em> (children of Adam/humanity). This vertical division undergirds v17: the dead in Sheol are in a third space — neither YHWH\'s heaven nor humanity\'s proper earth.</p>',
    "17": '<p><strong>lōʾ hāmētîm yĕhalĕlû-yāh wĕlōʾ kol-yōrĕdê dûmāh</strong> — "the dead do not praise the LORD, nor any who go down to silence" — <em>dûmāh</em> (silence, the realm of the dead) — Sheol as the land of silence. This is one of the most direct OT statements about the condition of the dead: they cannot praise. The same conviction appears in Ps 6:5 ("in death there is no remembrance of you; in Sheol who will give you thanks?") and Ps 88:10-12. This is not a denial of afterlife per se but an affirmation that Sheol is outside the covenant space of praise. Heb 2:12 (citing Ps 22:22) presents Christ\'s resurrection as precisely what reverses this: the risen Christ praises in the assembly, opening what Sheol had closed.</p>',
    "18": '<p><strong>waʾănaḥnû nĕbārēk yāh mēʿattāh wĕʿad-ʿôlām hallĕlûyāh</strong> — "but we — we will bless the LORD from this moment and forever. Praise the LORD!" — <em>waʾănaḥnû</em> (but we) is emphatic: in contrast to the dead who cannot praise, the living community takes up the obligation. The formula <em>mēʿattāh wĕʿad-ʿôlām</em> echoes Ps 113:2; the Egyptian Hallel frames time itself as praise-time. The closing <em>hallĕlûyāh</em> returns to the beginning of Ps 113, closing the liturgical bracket of the first Hallel pair.</p>',
  },
  "116": {
    "1": '<p><strong>ʾāhavtî kî-yišmaʿ yhwh ʾet-qôlî taḥănûnāy</strong> — "I love, because the LORD hears my voice, my supplications" — uniquely, <em>ʾāhavtî</em> (I love) has no stated object in Hebrew; the object of love is implied from the whole psalm. The verb is Qal perfect, a settled state: "I am in a state of love." <em>taḥănûnāy</em> (my supplications, cries for mercy, from <em>ḥānan</em>, to be gracious) is plural, suggesting repeated urgent requests over time, not a single prayer.</p>',
    "2": '<p><strong>kî-hiṭṭāh ʾoznô lî ûbĕyāmay ʾeqrāʾ</strong> — "because he has bent his ear to me; so for all my days I will call on him" — <em>hiṭṭāh ʾoznô</em> (inclined his ear, Hiphil of <em>nāṭāh</em>) — a vivid anthropomorphism: God tilts his ear downward to catch the prayer from below. The practical consequence is lifelong prayer: the experience of being heard generates a permanent posture of calling.</p>',
    "3": '<p><strong>ʾăpāpûnî ḥeblê-māwet ûmĕṣārê šĕʾôl mĕṣāʾûnî</strong> — "the ropes/cords of death surrounded me; the constrictions of Sheol found me" — <em>ḥeblê-māwet</em> (ropes/cords of death) — <em>ḥebel</em> means "cord/rope" and (with different vowels) "sorrow/pain"; the LXX reads <em>ōdines</em> (birth pangs). Either way the image is entrapment. <em>mĕṣārê šĕʾôl</em> (constrictions/straits of Sheol, from <em>ṣārar</em>, to bind, constrict) — Sheol closes in like a vise. <strong>ṣārāh wĕyāgôn ʾemṣāʾ</strong> — "distress and anguish I found."</p>',
    "4": '<p><strong>ûbĕšēm-yhwh ʾeqrāʾ ʾānnāh yhwh mallĕṭāh napšî</strong> — "then I called on the name of the LORD: \'O LORD, please — rescue my life!\'" — <em>ʾānnāh</em> (please, I beseech you) is the interjection of urgent petition (also Ps 118:25; Jon 1:14). <em>mallĕṭāh napšî</em> (rescue/deliver my life, Piel imperative of <em>mālaṭ</em>) — Piel is intensive: "snatch me out, pull me free." The entire saving event hinges on this single cry.</p>',
    "5": '<p><strong>ḥannûn yhwh wĕṣaddîq wĕʾĕlōhênû mĕraḥēm</strong> — "gracious is the LORD and righteous; our God is compassionate" — the same triad as Exod 34:6 and Ps 111:4 (<em>ḥannûn</em>, <em>ṣaddîq</em>, and <em>raḥûm</em>). In context the declaration is the psalmist\'s testimony after being heard: the rescue reveals what kind of God YHWH is. <em>mĕraḥēm</em> (showing compassion, Piel participle of <em>rāḥam</em>) derives from <em>reḥem</em> (womb) — divine compassion is womb-deep.</p>',
    "6": '<p><strong>šōmēr pĕtāʾyim yhwh dallōtî wĕlî yĕhôšîaʿ</strong> — "the LORD preserves the simple (<em>pĕtāʾyim</em>); I was brought low, and he saved me" — <em>pĕtāʾyim</em> (simple, naive, from <em>pāṭāh</em>, to be open/gullible) — the Proverbs vocabulary for those without experience. The LXX renders <em>nēpia</em> (infants, little ones). The "simple" need a guardian, not because they are foolish, but because they are inexperienced and open. <em>dallōtî</em> (I was brought low, Qal perfect of <em>dālal</em>, to hang low, be reduced) — he made no claim of merit; he simply fell, and God caught him.</p>',
    "7": '<p><strong>šûbî napšî limnûḥāyĕkî kî-yhwh gāmal ʿālāyĕkî</strong> — "return, O my soul, to your rest, for the LORD has been generous to you" — the psalmist speaks to his own <em>nepeš</em> (soul) — an interior dialogue rare in the Psalter (cf. Ps 42:5, 11; 103:1). <em>limnûḥāyĕkî</em> (to your resting place, from <em>nûaḥ</em>, to rest) — the same root as Noah\'s name. <em>gāmal</em> (to deal fully, to recompense, to be generous) — often used of both reward and punishment; here the generosity is the rescue just completed.</p>',
    "8": '<p><strong>kî ḥillaṣtā napšî mimmāwet ʾet-ʿênî min-dimʿāh ʾet-raglî middĕḥî</strong> — "for you have rescued my life from death, my eye from tears, my foot from stumbling" — <em>ḥillaṣ</em> (to draw out, rescue, Piel of <em>ḥālaṣ</em>) — originally to pull off a sandal, extended to extricating from any trap. The triple object (life from death; eye from tears; foot from stumbling) covers the whole person: existential, emotional, practical. The three rescue clauses mirror the three death-forms of v3.</p>',
    "9": '<p><strong>ʾethallēk lipnê yhwh bĕʾarṣôt haḥayyîm</strong> — "I will walk before the LORD in the land of the living" — <em>ʾethallēk</em> (Hithpael of <em>hālak</em>, to walk about, walk back and forth) — the Hithpael suggests ongoing, sustained walking, not a single stride. <em>lipnê yhwh</em> (before the LORD, in his presence) — covenant language for the life lived in YHWH\'s sight (Gen 17:1: "walk before me and be blameless"). <em>bĕʾarṣôt haḥayyîm</em> (in the land of the living) — the world of the living as opposed to Sheol.</p>',
    "10": '<p><strong>heʾĕmantî kî ʾădabbēr</strong> — "I believed/trusted, because I spoke" (or "I trusted, therefore I spoke") — the syntax is famously ambiguous: does <em>kî</em> introduce a result clause or a causal one? The LXX reads it as "I believed, therefore I spoke" (<em>episteusan, dio elalēsa</em>), which is the version Paul cites in 2 Cor 4:13 for his own apostolic speech: "Since we have the same spirit of faith according to what has been written, \'I believed, and so I spoke,\' we also believe, and so we also speak." <em>heʾĕmantî</em> (Hiphil perfect of <em>ʾāman</em>) = the root of <em>ʾāmēn</em>.</p>',
    "11": '<p><strong>ʾănî ʾāmartî bĕḥopsî kol-hāʾādām kōzēb</strong> — "I said in my panic/haste, \'All men are liars/faithless\'" — <em>bĕḥopsî</em> (in my alarm, haste, panic, from <em>ḥāpaz</em>, to be startled, flee in panic) — the same root as the sea\'s "flight" described in Ps 114:5. The panic-declaration that all humans are unreliable (<em>kōzēb</em>, a liar) is an extreme expression from within crisis — not a settled philosophical conviction. Paul quotes this in Rom 3:4 ("let God be true and every man a liar"), demonstrating how the same verse can be deployed in different theological contexts.</p>',
    "12": '<p><strong>māh-ʾāšîb layhwāh kol-tagmûlôhî ʿālay</strong> — "what shall I return/give back to the LORD for all his benefits toward me?" — <em>māh-ʾāšîb</em> (what shall I return?) — <em>šûb</em> (return, restore) frames the gift-and-return dynamic of covenant life: YHWH has given; the psalmist asks what return is appropriate. <em>tagmûlôhî</em> (his benefits, his full dealings, from <em>gāmal</em>) — the same root as v7\'s generosity; the psalmist is overwhelmed by the magnitude of the gift.</p>',
    "13": '<p><strong>kôs-yĕshûʿôt ʾeśśāʾ ûbĕšēm yhwh ʾeqrāʾ</strong> — "I will lift up the cup of salvations and call on the name of the LORD" — <em>kôs-yĕshûʿôt</em> (cup of salvations) — the plural <em>yĕshûʿôt</em> (salvations, rescues) is significant: not a single rescue but multiple or great salvations. Ellicott identifies the <em>kôs</em> with the drink offering (<em>nesek</em>) accompanying festival sacrifices (Num 15:5-10). The psalmist\'s return to God is not payment but further worship. The NT Last Supper\'s "cup of blessing" (1 Cor 10:16) stands in this tradition.</p>',
    "14": '<p><strong>nĕdāray layhwāh ʾăšallēm neged-nāʾ lĕkhol-ʿammô</strong> — "my vows to the LORD I will pay, now in the presence of all his people" — <em>nĕdāray</em> (my vows, from <em>nādar</em>, to vow) — the psalmist had made vows during the crisis (v4: "I called on the name of the LORD"); now he fulfills them publicly. The public fulfillment of vows is liturgically essential: the congregation witnesses and validates the testimony. This verse repeats verbatim as v18, forming a refrain around the central v15.</p>',
    "15": '<p><strong>yāqār bĕʿênê yhwh hammāwĕtāh laḥăsîdāyw</strong> — "precious/costly in the eyes of the LORD is the death of his faithful ones (<em>ḥăsîdîm</em>)" — the most theologically debated verse in the psalm. <em>yāqār</em> (precious, costly, rare, heavy) — the ambiguity is productive: (1) the death of his faithful is valued by God (making martyrdom meritorious); (2) the death of his faithful is costly to God (he grieves it, takes it seriously). Most modern scholars and the context favor (2): God does not regard the death of his <em>ḥăsîdîm</em> lightly — he takes it seriously, which is why he rescues (vv3-8) and why the vow-fulfillment matters (vv13-18). The <em>ḥăsîdîm</em> are the covenant people at their most devoted.</p>',
    "16": '<p><strong>ʾānnāh yhwh kî-ʾănî ʿabdĕkā ʾănî-ʿabdĕkā ben-ʾămātĕkā pittaḥtā lĕmôsērāy</strong> — "O LORD, I am your servant — your servant, son of your handmaid; you have loosed my bonds" — <em>ben-ʾămātĕkā</em> (son of your handmaid/female servant) — a son born in the owner\'s household, a hereditary servant from birth rather than one acquired. This heightens the covenantal intimacy. Ps 86:16 uses the identical phrase. <em>pittaḥtā lĕmôsērāy</em> — "you have opened/loosed my bonds/fetters" — <em>pātaḥ</em> (to open, loosen) applied to <em>mōsērôt</em> (bonds, fetters) picks up the ropes of death from v3.</p>',
    "17": '<p><strong>lĕkā ʾezbaḥ zebaḥ tôdāh ûbĕšēm yhwh ʾeqrāʾ</strong> — "to you I will offer a sacrifice of thanksgiving (<em>tôdāh</em>) and call on the name of the LORD" — the <em>zebaḥ tôdāh</em> (thanksgiving sacrifice) was a specific cultic category in Lev 7:11-15: a peace offering made when someone had been delivered from danger (illness, sea crossing, prison, desert). Ps 116 is itself a <em>tôdāh</em> psalm — both the literary form (testimony of rescue followed by praise) and the cultic act it likely accompanied.</p>',
    "18": '<p><strong>nĕdāray layhwāh ʾăšallēm neged-nāʾ lĕkhol-ʿammô</strong> — verbatim repetition of v14, forming the refrain that frames v15. The public fulfillment of vows (v14 → v15 → v18) moves from obligation to declaration of God\'s seriousness about his servants\' deaths to completion. The structural repetition signals liturgical performance: the congregation hears the vow-fulfillment formula twice, around the theologically central v15.</p>',
    "19": '<p><strong>bĕḥaṣrôt bêt-yhwh bĕtôkēkî yĕrûšālāim hallĕlûyāh</strong> — "in the courtyards of the house of the LORD, in your midst, O Jerusalem. Praise the LORD!" — the psalm closes with geographic specificity: the vow is fulfilled not just before "all his people" (vv14,18) but in the temple courts, in Jerusalem. This is the pilgrimage psalm\'s destination — the pilgrim arrives and fulfills his vow. <em>hallĕlûyāh</em> closes the psalm and opens directly into Ps 117, the briefest and most universal of the Hallel psalms.</p>',
  },
  "117": {
    "1": '<p><strong>hallĕlû ʾet-yhwh kol-gôyim šabbĕḥûhû kol-hāʾummîm</strong> — "praise the LORD, all nations! Extol/laud him, all peoples!" — Ps 117 is the shortest psalm and the shortest chapter in the Bible. Its two commands address not Israel but the nations: <em>gôyim</em> (nations, Gentiles) and <em>ʾummîm</em> (peoples, tribes, ethnic groups) — the entire sweep of humanity. The verb <em>šābaḥ</em> (to praise, extol, laud) appears relatively rarely in the Psalter and has the connotation of public acclamation. Paul quotes this verse in Rom 15:11 as his fourth OT proof-text that God always intended the Gentiles to praise him — alongside Deut 32:43, 2 Sam 22:50, and Isa 11:10. The universal call is not a post-Resurrection innovation; it is embedded in the Psalter\'s own vision.</p>',
    "2": '<p><strong>kî gābar ʿālênû ḥasdô wĕʾĕmet-yhwh lĕʿôlām hallĕlûyāh</strong> — "for his steadfast love (<em>ḥesed</em>) has prevailed/been mighty over us, and the faithfulness (<em>ʾĕmet</em>) of the LORD is forever. Praise the LORD!" — <em>gābar</em> (to be strong, prevail, be mighty, overcome) is an unusual verb to pair with <em>ḥesed</em>. Normally <em>ḥesed</em> is described as "great" or "enduring"; here it "prevails" — it overcomes, triumphs, wins. The two pillars of divine character — <em>ḥesed</em> (covenant love) and <em>ʾĕmet</em> (faithfulness, reliability) — recur from Exod 34:6 throughout the Psalter. Here they are the grounds on which the nations are called to praise: not Israel\'s military victories but YHWH\'s relentless covenant love, which is mighty enough to claim even the Gentiles.</p>',
  },
}

def main():
    existing = load_comm('mkt-original', 'psalms')
    merge_comm(existing, PSALMS)
    save_comm('mkt-original', 'psalms', existing)
    print('Psalms 111-117 mkt-original written.')

if __name__ == '__main__':
    main()
